/* ===============================================================
   n8n Function node – Rapport quotidien MLC / MATA
   Sorties : 
     - rapport (texte brut, identique à votre format actuel)
     - rapport_html (HTML responsive)
   =============================================================== */

/* 1. Récupération de l’objet jour ───────────────────────────── */
let day = items[0].json;
if (Array.isArray(day)) day = day[0];

/* 2. Vérification minimale */
if (!day?.summary || !day?.classement || !day?.details) {
  throw new Error('Le JSON ne contient pas summary / classement / details.');
}

/* 3. Petites fonctions utiles */
const fcfa   = v => `${Number(v || 0).toLocaleString('fr-FR')} FCFA`;
const frDate = iso => { if (!iso) return ''; const [y,m,d] = iso.split('-'); return `${d}/${m}/${y}`; };
const line   = len => '—'.repeat(len); // séparateur
const esc    = s => String(s ?? '').replace(/[&<>"]/g, t => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[t]));

/* 4. Pré-calculs globaux ───────────────────────────────────── */
const { summary, classement, details } = day;
const revenus   = (classement || []).reduce((s,l)=>s+(l.revenus || 0), 0);
const depenses  = summary?.depenses?.total || 0;
const benefNet  = revenus - depenses;

/*** Panier moyen & total (MATA) ***/
const panierMoyen = summary?.courses_mata?.panier_moyen ?? 0;
const panierTotal = summary?.courses_mata?.panier_total_jour ?? 0;

/* === NOUVEAU BLOC : Courses internes par point de vente ===== */
const internesPV = (summary?.courses_mata?.par_point_vente || [])
  .filter(pv => (pv?.nombre_courses_internes || 0) > 0)
  .map(pv => `• ${pv.point_de_vente} : ${pv.nombre_courses_internes} interne${pv.nombre_courses_internes>1?'s':''}`)
  .join('\n');

/* 4-1  RÉSUMÉ (texte brut) ----------------------------------- */
const bloc1 = [
  `${line(60)}`,
  `📊  RÉSUMÉ – ${frDate(day.date)}`,
  `${line(60)}`,
  `${summary?.total_courses || 0} courses au total`,
  `Panier moyen  : ${fcfa(panierMoyen)}`,
  `Panier total  : ${fcfa(panierTotal)}`,
  `Dépenses      : ${fcfa(depenses)}`,
  `Revenus       : ${fcfa(revenus)}`,
  `Bénéfice      : ${fcfa(benefNet)}`,
  ''
].join('\n');

const blocInternes = internesPV
  ? [
      `${line(60)}`,
      `🏠  COURSES INTERNES (MATA)`,
      `${line(60)}`,
      internesPV,
      ''
    ].join('\n')
  : '';

/* 4-2  CLASSEMENT (texte brut) ------------------------------- */
const rangEmoji = ['🥇','🥈','🥉'];
const bloc2Lines = [...(classement || [])]
  .sort((a,b)=> (b?.benefice||0) - (a?.benefice||0))
  .map((l,i)=>{
    const badge = rangEmoji[i] ?? '▪️';
    return `${badge}  ${l.livreur_nom} — ${l.total_courses} course(s)\n` +
           `    Revenus  ${fcfa(l.revenus)} | Dépenses  ${fcfa(l.depenses_totales)} | Bénéfice  ${fcfa(l.benefice)}`;
  });
const bloc2 = [
  `${line(60)}`,
  `🚚  CLASSEMENT DES LIVREURS`,
  `${line(60)}`,
  bloc2Lines.join('\n\n') || 'Aucune donnée.',
  ''
].join('\n');

/* 4-3  ANALYSE DES SEUILS (texte brut) ----------------------- */
const paniersLow = summary?.courses_mata?.panier_inf_seuil ?? 0;
const zonesLow   = summary?.courses_mlc?.sans_abonnement?.par_zone?.zone1_1750 ?? 0;
const bloc3 = [
  `${line(60)}`,
  `🧐  ANALYSE DES SEUILS`,
  `${line(60)}`,
  `• Paniers MATA < ${fcfa(day.seuil_mata_panier)} : ${paniersLow}`,
  `• Courses MLC < ${fcfa(day.seuil_mlc)} : ${zonesLow || '0'} anomalie(s)`,
  ''
].join('\n');

/* 4-4  GÉOGRAPHIE (texte brut) ------------------------------- */
const geo = (summary?.courses_mata?.par_point_vente || [])
  .map(pv=>`• ${pv.point_de_vente} : ${pv.nombre_courses} course${pv.nombre_courses>1?'s':''}`)
  .join('\n');
const bloc4 = [
  `${line(60)}`,
  `📍  RÉPARTITION GÉOGRAPHIQUE (MATA)`,
  `${line(60)}`,
  geo || 'Aucune donnée.',
  ''
].join('\n');

/* 4-5  DÉPENSES DÉTAILLÉES (texte brut) ---------------------- */
const depLines = (details || [])
  .filter(d=> (d.total_courses||0)>0 || (d?.depenses?.total||0)>0)
  .map(d =>
`${d.livreur_nom}\n   ⛽ ${fcfa(d?.depenses?.carburant)}  |  🚔 ${fcfa(d?.depenses?.police)}  |  🔧 ${fcfa(d?.depenses?.reparations)}  |  💸 Total ${fcfa(d?.depenses?.total)}`);
const bloc5 = [
  `${line(60)}`,
  `💸  DÉPENSES DÉTAILLÉES`,
  `${line(60)}`,
  depLines.join('\n\n') || 'Aucune dépense.',
  ''
].join('\n');

/* 4-6  RÉPARTITION DES TYPES (texte brut) -------------------- */
const mlc    = summary?.courses_mlc || {};
const autres = summary?.courses_autre || { nombre: 0, prix_total: 0 };
const z      = mlc?.sans_abonnement?.par_zone || {};
const bloc6 = [
  `${line(60)}`,
  `🔖  RÉPARTITION DES TYPES DE COURSES`,
  `${line(60)}`,
  `• Avec abonnement    : ${mlc?.avec_abonnement?.total ?? 0}  (extras : ${mlc?.avec_abonnement?.nombre_extras ?? 0})`,
  `• Sans abonnement    : ${mlc?.sans_abonnement?.total ?? 0}`,
  `     - Zone 1 : ${z.zone1_1750 ?? 0} | Zone 2 : ${z.zone2_2000 ?? 0} | Zone 3 : ${z.zone3_3000 ?? 0} | Autre : ${z.autre ?? 0}`,
  `• Autres             : ${autres?.nombre ?? 0}  |  Montant ${fcfa(autres?.prix_total ?? 0)}`,
  ''
].join('\n');

/* 5. Rapport final (texte brut) ------------------------------ */
const rapport = bloc1 + blocInternes + bloc2 + bloc3 + bloc4 + bloc5 + bloc6;

/* =========================
   VERSION HTML RESPONSIVE
   ========================= */

const css = `
  .wrap { font-family: Arial, Helvetica, sans-serif; color:#0f172a; }
  h2 { margin:0 0 8px 0; font-size:18px; }
  h3 { margin:18px 0 8px 0; font-size:16px; }
  .card { border:1px solid #e5e7eb; border-radius:12px; padding:12px; margin:8px 0; background:#ffffff; }
  .muted { color:#475569; }
  .kpi { display:grid; grid-template-columns: repeat(2, minmax(0,1fr)); gap:8px; }
  .kpi .item { padding:8px; border:1px solid #e5e7eb; border-radius:10px; }
  table { width:100%; border-collapse:collapse; }
  th, td { padding:8px; border:1px solid #e5e7eb; vertical-align:top; }
  th { background:#f8fafc; text-align:left; }
  .right { text-align:right; }
  .small { font-size:12px; }
  @media (max-width:600px) {
    .kpi { grid-template-columns: 1fr; }
    table { font-size:12px; }
    th, td { padding:6px; }
  }
`;

/* Résumé HTML */
const htmlResume = `
  <div class="card">
    <h2>📊 RÉSUMÉ – ${esc(frDate(day.date))}</h2>
    <div class="kpi">
      <div class="item"><div class="muted small">Courses (total)</div><div><strong>${esc(summary?.total_courses ?? 0)}</strong></div></div>
      <div class="item"><div class="muted small">Panier moyen</div><div><strong>${esc(fcfa(panierMoyen))}</strong></div></div>
      <div class="item"><div class="muted small">Panier total</div><div><strong>${esc(fcfa(panierTotal))}</strong></div></div>
      <div class="item"><div class="muted small">Dépenses</div><div><strong>${esc(fcfa(depenses))}</strong></div></div>
      <div class="item"><div class="muted small">Revenus</div><div><strong>${esc(fcfa(revenus))}</strong></div></div>
      <div class="item"><div class="muted small">Bénéfice</div><div><strong>${esc(fcfa(benefNet))}</strong></div></div>
    </div>
  </div>
`;

/* Courses internes HTML */
const htmlInternes = (internesPV)
  ? `
  <div class="card">
    <h3>🏠 COURSES INTERNES (MATA)</h3>
    <pre class="small" style="white-space:pre-wrap; margin:0;">${esc(internesPV)}</pre>
  </div>`
  : '';

/* Classement HTML */
const classementSorted = [...(classement || [])].sort((a,b)=> (b?.benefice||0) - (a?.benefice||0));
const htmlClassementRows = classementSorted.map((l,i)=>`
  <tr>
    <td>${esc((['🥇','🥈','🥉'][i] ?? '▪️'))}</td>
    <td>${esc(l?.livreur_nom ?? '')}</td>
    <td class="right">${esc(l?.total_courses ?? 0)}</td>
    <td class="right">${esc(fcfa(l?.revenus ?? 0))}</td>
    <td class="right">${esc(fcfa(l?.depenses_totales ?? 0))}</td>
    <td class="right"><strong>${esc(fcfa(l?.benefice ?? 0))}</strong></td>
  </tr>
`).join('');

const htmlClassement = `
  <div class="card">
    <h3>🚚 CLASSEMENT DES LIVREURS</h3>
    <table>
      <thead><tr>
        <th>#</th><th>Livreur</th><th class="right">Courses</th><th class="right">Revenus</th><th class="right">Dépenses</th><th class="right">Bénéfice</th>
      </tr></thead>
      <tbody>
        ${htmlClassementRows || `<tr><td colspan="6" class="small muted">Aucune donnée.</td></tr>`}
      </tbody>
    </table>
  </div>
`;

/* Analyse des seuils HTML */
const htmlSeuils = `
  <div class="card">
    <h3>🧐 ANALYSE DES SEUILS</h3>
    <ul class="small" style="margin:0; padding-left:18px;">
      <li>Paniers MATA &lt; ${esc(fcfa(day.seuil_mata_panier))} : <strong>${esc(paniersLow)}</strong></li>
      <li>Courses MLC &lt; ${esc(fcfa(day.seuil_mlc))} : <strong>${esc(zonesLow || 0)}</strong> anomalie(s)</li>
    </ul>
  </div>
`;

/* Répartition géographique HTML */
const geoList = (summary?.courses_mata?.par_point_vente || [])
  .map(pv=>`<li>${esc(pv.point_de_vente)} : <strong>${esc(pv.nombre_courses)}</strong> course${pv.nombre_courses>1?'s':''}</li>`)
  .join('');
const htmlGeo = `
  <div class="card">
    <h3>📍 RÉPARTITION GÉOGRAPHIQUE (MATA)</h3>
    <ul class="small" style="margin:0; padding-left:18px;">
      ${geoList || `<li class="muted">Aucune donnée.</li>`}
    </ul>
  </div>
`;

/* Dépenses détaillées HTML */
const depRows = (details || [])
  .filter(d => (d?.total_courses||0)>0 || (d?.depenses?.total||0)>0)
  .map(d => `
    <tr>
      <td>${esc(d?.livreur_nom ?? '')}</td>
      <td class="right">${esc(fcfa(d?.depenses?.carburant ?? 0))}</td>
      <td class="right">${esc(fcfa(d?.depenses?.police ?? 0))}</td>
      <td class="right">${esc(fcfa(d?.depenses?.reparations ?? 0))}</td>
      <td class="right"><strong>${esc(fcfa(d?.depenses?.total ?? 0))}</strong></td>
    </tr>
  `).join('');
const htmlDep = `
  <div class="card">
    <h3>💸 DÉPENSES DÉTAILLÉES</h3>
    <table>
      <thead><tr>
        <th>Livreur</th><th class="right">Carburant</th><th class="right">Police</th><th class="right">Réparations</th><th class="right">Total</th>
      </tr></thead>
      <tbody>${depRows || `<tr><td colspan="5" class="small muted">Aucune dépense.</td></tr>`}</tbody>
    </table>
  </div>
`;

/* Répartition des types HTML */
const htmlTypes = `
  <div class="card">
    <h3>🔖 RÉPARTITION DES TYPES DE COURSES</h3>
    <ul class="small" style="margin:0; padding-left:18px;">
      <li>Avec abonnement : <strong>${esc(mlc?.avec_abonnement?.total ?? 0)}</strong> (extras : ${esc(mlc?.avec_abonnement?.nombre_extras ?? 0)})</li>
      <li>Sans abonnement : <strong>${esc(mlc?.sans_abonnement?.total ?? 0)}</strong>
        <div class="muted">Zone 1 : ${esc(z.zone1_1750 ?? 0)} | Zone 2 : ${esc(z.zone2_2000 ?? 0)} | Zone 3 : ${esc(z.zone3_3000 ?? 0)} | Autre : ${esc(z.autre ?? 0)}</div>
      </li>
      <li>Autres : <strong>${esc(autres?.nombre ?? 0)}</strong> — Montant ${esc(fcfa(autres?.prix_total ?? 0))}</li>
    </ul>
  </div>
`;

/* Assemblage HTML */
const rapport_html = `
<!doctype html>
<html lang="fr">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Rapport quotidien – ${esc(frDate(day.date))}</title>
<style>${css}</style>
</head>
<body>
  <div class="wrap">
    ${htmlResume}
    ${htmlInternes}
    ${htmlClassement}
    ${htmlSeuils}
    ${htmlGeo}
    ${htmlDep}
    ${htmlTypes}
    <div class="small muted" style="margin-top:12px;">Généré automatiquement.</div>
  </div>
</body>
</html>
`.trim();

/* 6. Sortie n8n --------------------------------------------- */
return [{
  json: {
    date: day.date,
    rapport,        // texte brut
    rapport_html    // HTML
  }
}];

