// n8n Function node
// Entrée attendue: items[0].json.stats = { statDay, statWeek, statMonth, ... }
// Sortie: un item avec html global + html_statDay/html_statWeek/html_statMonth et text

function fmtNumber(n) {
  if (n === null || n === undefined || n === '') return '';
  const x = Number(n);
  if (Number.isNaN(x)) return String(n);
  return x.toLocaleString('fr-FR');
}

function fmtPack(v) {
  if (v === null || v === undefined || v === '') return '';
  return String(v);
}

function fmtDate(d) {
  if (!d) return '';
  return String(d);
}

function fmtRepartition(obj) {
  if (!obj || typeof obj !== 'object') return '';
  return Object.entries(obj).map(([k, v]) => `${k}: ${v}`).join(', ');
}

/**
 * Construit un tableau HTML et un bloc texte.
 * @param {string} periodLabel - Titre (ex: "StatWeek / Clients")
 * @param {object} periodObj   - Objet période { dateDebut, dateFin, clients: [...] }
 * @param {object} options     - { withInterpretation: boolean, interpretationText?: string }
 */
function buildTable(periodLabel, periodObj, options = {}) {
  const { withInterpretation = false, interpretationText = '' } = options;

  const baseHeaders = [
    'Nom', 'Téléphone', 'Total commandes', 'Dernière commande',
    'MLC Abonnement', 'MLC Simple', 'Nombre supplément',
    'Pack restant', 'Total courses (FCFA)', 'Somme suppléments (FCFA)', 'Répartition livreur'
  ];
  const headers = withInterpretation ? [...baseHeaders, 'Interprétation'] : baseHeaders;

  let rowsHtml = '';
  let rowsText = '';

  const clients = Array.isArray(periodObj?.clients) ? periodObj.clients : [];

  const periodRange = (periodObj?.dateDebut && periodObj?.dateFin)
    ? ` (${periodObj.dateDebut} → ${periodObj.dateFin})`
    : '';

  if (clients.length === 0) {
    const colspan = headers.length;
    rowsHtml += `<tr><td colspan="${colspan}" style="text-align:center;">pas d'estimation!</td></tr>`;
    rowsText += `- pas d'estimation!\n`;
  } else {
    const sorted = clients
      .slice()
      .sort((a, b) => (b.total_commandes || 0) - (a.total_commandes || 0) || String(a.nom).localeCompare(String(b.nom)));

    sorted.forEach((c, idx) => {
      const line = {
        nom: c.nom || '',
        tel: c.telephone || '',
        totCmd: fmtNumber(c.total_commandes),
        last: fmtDate(c.date_derniere_commande),
        abo: fmtNumber(c.mlc_abonnement),
        simple: fmtNumber(c.mlc_simple),
        nbSup: fmtNumber(c.nombre_supplement),
        pack: fmtPack(c.pack_restant),
        totalCourses: fmtNumber(c.total_courses),
        sommeSupp: fmtNumber(c.somme_supplements),
        repart: fmtRepartition(c.repartition_livreur),
      };

      // Construire les cellules "classiques"
      let tds = `
        <td>${line.nom}</td>
        <td>${line.tel}</td>
        <td style="text-align:right;">${line.totCmd}</td>
        <td>${line.last}</td>
        <td style="text-align:right;">${line.abo}</td>
        <td style="text-align:right;">${line.simple}</td>
        <td style="text-align:right;">${line.nbSup}</td>
        <td>${line.pack}</td>
        <td style="text-align:right;">${line.totalCourses}</td>
        <td style="text-align:right;">${line.sommeSupp}</td>
        <td>${line.repart}</td>
      `;

      // Ajouter la colonne "Interprétation" une seule fois (rowspan = nb de clients)
      if (withInterpretation && idx === 0) {
        const safeInterp = interpretationText || '';
        tds += `<td rowspan="${sorted.length}" style="vertical-align:top; white-space:pre-wrap;">${safeInterp}</td>`;
      }

      rowsHtml += `<tr>${tds}</tr>`;

      rowsText += `- ${line.nom} (${line.tel}) | Cmd: ${line.totCmd} | Dernière: ${line.last} | Abon.: ${line.abo} | `
        + `Simple: ${line.simple} | Suppl.: ${line.nbSup} | Pack: ${line.pack} | Courses: ${line.totalCourses} FCFA | `
        + `Suppl. tot.: ${line.sommeSupp} FCFA | Livreur(s): ${line.repart}\n`;
    });

    // Ajouter le bloc d'interprétation à la fin du texte si demandé
    if (withInterpretation && interpretationText) {
      rowsText += `\n[Interprétation]\n${interpretationText}\n`;
    }
  }

  const tableHtml = `
    <h3 style="margin:12px 0;">${periodLabel}${periodRange}</h3>
    <table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse; width:100%;">
      <thead>
        <tr>
          ${headers.map(h => `<th style="text-align:left;">${h}</th>`).join('')}
        </tr>
      </thead>
      <tbody>
        ${rowsHtml}
      </tbody>
    </table>
  `;

  const textBlock = `${periodLabel}${periodRange}\n${rowsText}`;

  return { tableHtml, textBlock };
}

// --- Récupération des stats d'entrée
const stats = (items[0]?.json?.stats) || {};
const {
  statDay = {},
  statWeek = {},
  statMonth = {},
  interpretationWeek,   // au cas où l'interprétation serait aussi au niveau racine
  interpretationMonth,   // idem
} = stats;

// Préférence: lire d'abord l'interprétation dans l'objet période
const interpWeek = statWeek?.interpretationWeek ?? interpretationWeek ?? '';
const interpMonth = statMonth?.interpretationMonth ?? interpretationMonth ?? '';

// Construire les trois tableaux
const day   = buildTable('StatDay / Clients',   statDay,  { withInterpretation: false });
const week  = buildTable('StatWeek / Clients',  statWeek, { withInterpretation: true,  interpretationText: interpWeek });
const month = buildTable('StatMonth / Clients', statMonth,{ withInterpretation: true,  interpretationText: interpMonth });

const html = `
  <div style="font-family:Arial, Helvetica, sans-serif; font-size:13px;">
    ${day.tableHtml}
    ${week.tableHtml}
    ${month.tableHtml}
  </div>
`;

const text = day.textBlock + '\n' + week.textBlock + '\n' + month.textBlock;

return [
  {
    json: {
      html,
      text,
      html_statDay: day.tableHtml,
      html_statWeek: week.tableHtml,
      html_statMonth: month.tableHtml,
    }
  }
];
